#include<bits/stdc++.h>
using namespace std;
int main() {
	long long n, bin[200], glma[200], m, k = 0, l = 0, a, len = 0, y = 0;
	cin >> a >> n ;
	m = n;
	for (; m != 0;) {
		bin[k] = m % 2;
		k++;
		l++;

		m /= 2;

	}
	glma[k] = bin[k];
	k--;
	for (int i = k; i >= 0; i--) {
		glma[i] = (bin[i + 1] ^ bin[i]) % 2;
		k--;
	}
	for(int i=l;0<a-i;i++){
		cout<<"0";
	}
	for (int i = l - 1 ; i >= 0; i--) {

		cout << glma[i];


	}
	return 0;
}
